#if UNITY_EDITOR
using System.Collections.Generic;
using UnityEditor;
using UnityEngine;

/// <summary>
/// Editor customizado de ItemData (Tarefa "Itens Consumíveis" — Ferramentas no
/// Unity):
///
/// 1) Mostra apenas os campos relevantes para o <see cref="ItemData.effectType"/>
///    escolhido (os campos "Efeito Temporário no Player" só aparecem com
///    "selfBuff" activo; os campos de cada item pré-programado só aparecem
///    com o "effectType" correspondente; os campos de feedback geral só
///    aparecem se "effectType" != Nenhum).
/// 2) Mostra avisos de validação (itemId/displayName vazios, effectType sem
///    "usableByPlayer", Aderência sem "selfBuff", raio <= 0, etc).
/// 3) Para efeitos em área (Sono/Resina/Congelamento), lista quais EnemyData
///    do projecto já estão configurados para reagir a este item (por itemId
///    "do GDD" ou por "otherItemEffects") — ajuda a verificar imunidades.
/// 4) Em Play Mode, um botão "Testar Efeito no Player" aplica o efeito ao
///    PlayerItemUser da cena (via <see cref="PlayerItemUser.ApplyItemEffect"/>),
///    sem gastar inventário — útil para balancear valores rapidamente.
/// </summary>
[CustomEditor(typeof(ItemData))]
public class ItemDataEditor : Editor
{
    // Tipos de efeito "em área" (Sono, Resina, Congelamento, Invisibilidade).
    // Declarado ANTES de EffectTypeFields: a ordem de inicialização de campos
    // estáticos em C# segue a ordem textual, e EffectTypeFields referencia este array.
    private static readonly ConsumableEffectType[] AreaEffectTypes =
    {
        ConsumableEffectType.Sono, ConsumableEffectType.Resina,
        ConsumableEffectType.Congelamento, ConsumableEffectType.Invisibilidade,
    };

    // Campos cuja visibilidade depende de "effectType".
    private static readonly Dictionary<string, ConsumableEffectType[]> EffectTypeFields = new Dictionary<string, ConsumableEffectType[]>
    {
        { "effectRadius", AreaEffectTypes },
        { "affectAllInRadius", AreaEffectTypes },
        { "sleepDuration", new[] { ConsumableEffectType.Sono } },
        { "resinDuration", new[] { ConsumableEffectType.Resina } },
        { "resinFlyingPullSpeed", new[] { ConsumableEffectType.Resina } },
        { "resinAquaticSinkSpeed", new[] { ConsumableEffectType.Resina } },
        { "invisibilityDuration", new[] { ConsumableEffectType.Invisibilidade } },
        { "freezeDuration", new[] { ConsumableEffectType.Congelamento } },
        { "shieldMaxDuration", new[] { ConsumableEffectType.Escudo } },
        { "shieldIgnoresSpecialDeaths", new[] { ConsumableEffectType.Escudo } },
        { "speedBoostMultiplier", new[] { ConsumableEffectType.Velocidade } },
        { "speedBoostDuration", new[] { ConsumableEffectType.Velocidade } },
        { "highlightRadius", new[] { ConsumableEffectType.DestacarColecionaveis } },
        { "highlightDuration", new[] { ConsumableEffectType.DestacarColecionaveis } },
        { "highlightedPickupTypes", new[] { ConsumableEffectType.DestacarColecionaveis } },
        { "highlightColor", new[] { ConsumableEffectType.DestacarColecionaveis } },
        { "regenHearts", new[] { ConsumableEffectType.Regeneracao } },
        { "regenDuration", new[] { ConsumableEffectType.Regeneracao } },
        { "currentImmunityDuration", new[] { ConsumableEffectType.ImunidadeCorrente } },
        { "windBurstForce", new[] { ConsumableEffectType.ImpulsoVertical } },
        { "windBurstMaxHeight", new[] { ConsumableEffectType.ImpulsoVertical } },
    };

    private static readonly string[] SelfBuffFields =
    {
        "selfBuffDuration", "selfBuffKnockbackMultiplier", "selfBuffSkidGripMultiplier",
    };

    private static readonly string[] FeedbackFields =
    {
        "effectActivateSfx", "effectEndSfx", "effectVfxPrefab",
    };

    // itemId "do GDD" reconhecidos directamente por EnemyStatusEffectReceiver.ApplyItem,
    // e o EnemyStatusEffect correspondente (para a secção de compatibilidade).
    private static readonly Dictionary<string, (ConsumableEffectType type, EnemyStatusEffect effect, string flagField)> GddEnemyItems =
        new Dictionary<string, (ConsumableEffectType, EnemyStatusEffect, string)>
    {
        { "flor_do_silencio", (ConsumableEffectType.Sono, EnemyStatusEffect.Sleep, "canSleepFromSilenceFlower") },
        { "resina_antiga", (ConsumableEffectType.Resina, EnemyStatusEffect.Trap, "canBeTrappedByAncientResin") },
        { "po_dourado", (ConsumableEffectType.Invisibilidade, EnemyStatusEffect.LoseTarget, "losesTargetFromGoldenDust") },
        { "cristal_de_gelo", (ConsumableEffectType.Congelamento, EnemyStatusEffect.Freeze, "canBeFrozenByIceCrystal") },
    };

    public override void OnInspectorGUI()
    {
        serializedObject.Update();
        var item = (ItemData)target;

        SerializedProperty prop = serializedObject.GetIterator();
        bool enterChildren = true;
        while (prop.NextVisible(enterChildren))
        {
            enterChildren = false;
            if (prop.name == "m_Script") continue;
            if (!ShouldShow(prop.name, item)) continue;

            EditorGUILayout.PropertyField(prop, true);
        }

        serializedObject.ApplyModifiedProperties();

        EditorGUILayout.Space();
        DrawValidationWarnings(item);

        if (item.effectType == ConsumableEffectType.Sono || item.effectType == ConsumableEffectType.Resina
            || item.effectType == ConsumableEffectType.Congelamento || item.effectType == ConsumableEffectType.Invisibilidade)
        {
            EditorGUILayout.Space();
            DrawEnemyCompatibilitySection(item);
        }

        EditorGUILayout.Space();
        DrawTestButton(item);
    }

    private bool ShouldShow(string fieldName, ItemData item)
    {
        if (System.Array.IndexOf(SelfBuffFields, fieldName) >= 0)
            return item.selfBuff;

        if (System.Array.IndexOf(FeedbackFields, fieldName) >= 0)
            return item.effectType != ConsumableEffectType.Nenhum;

        if (EffectTypeFields.TryGetValue(fieldName, out var types))
            return System.Array.IndexOf(types, item.effectType) >= 0;

        return true;
    }

    // ------------------------------------------------------------
    // Avisos de validação
    // ------------------------------------------------------------

    private void DrawValidationWarnings(ItemData item)
    {
        if (string.IsNullOrEmpty(item.itemId))
            EditorGUILayout.HelpBox("\"itemId\" está vazio — necessário para inventário, drops, save e condições de diálogo.", MessageType.Warning);

        if (string.IsNullOrEmpty(item.displayName))
            EditorGUILayout.HelpBox("\"displayName\" está vazio.", MessageType.Warning);

        if (item.effectType != ConsumableEffectType.Nenhum && !item.usableByPlayer)
            EditorGUILayout.HelpBox("\"effectType\" está definido mas \"usableByPlayer\" está desligado — o efeito nunca será aplicado (PlayerItemUser ignora itens não usáveis).", MessageType.Warning);

        if (item.effectType == ConsumableEffectType.Aderencia && !item.selfBuff)
            EditorGUILayout.HelpBox("\"Aderência\" usa os campos \"Efeito Temporário no Player\" (selfBuff*) — active \"selfBuff\" acima e configure a duração/multiplicadores.", MessageType.Warning);

        bool isAreaEffect = System.Array.IndexOf(AreaEffectTypes, item.effectType) >= 0;

        if (isAreaEffect)
        {
            if (item.effectRadius <= 0f)
                EditorGUILayout.HelpBox("\"effectRadius\" <= 0 — este item usará o raio por defeito de PlayerItemUser.useRadius da cena.", MessageType.Info);

            if (!item.affectAllInRadius)
                EditorGUILayout.HelpBox("\"affectAllInRadius\" desligado — só o inimigo mais próximo dentro do raio será afectado.", MessageType.Info);

            if (!GddEnemyItems.ContainsKey(item.itemId))
                EditorGUILayout.HelpBox("Este \"itemId\" não corresponde a nenhum item \"do GDD\" reconhecido directamente por EnemyStatusEffectReceiver. Para que afecte inimigos, adicione uma entrada em EnemyData → Interacção com Itens → \"Outros Itens Globais/Regionais\" (otherItemEffects), apontando para este item e o EnemyStatusEffect desejado.", MessageType.Info);
        }

        if (item.effectType == ConsumableEffectType.DestacarColecionaveis && (item.highlightedPickupTypes == null || item.highlightedPickupTypes.Count == 0))
            EditorGUILayout.HelpBox("Lista de tipos de coleccionável vazia — TODOS os tipos serão destacados (comportamento intencional, ver tooltip).", MessageType.Info);

        if (item.effectType == ConsumableEffectType.Escudo && item.shieldMaxDuration <= 0f)
            EditorGUILayout.HelpBox("\"shieldMaxDuration\" = 0 — o escudo só termina ao bloquear um golpe (sem limite de tempo).", MessageType.Info);

        if (item.consumable && item.maxQuantity < 1)
            EditorGUILayout.HelpBox("\"maxQuantity\" deve ser >= 1 para um item consumível.", MessageType.Warning);

        if (item.itemType == ItemType.Tesouro && item.usableByPlayer)
            EditorGUILayout.HelpBox("Item do tipo \"Tesouro\" marcado como \"usableByPlayer\" — confirme que isto é intencional (tesouros normalmente só se vendem).", MessageType.Info);
    }

    // ------------------------------------------------------------
    // Compatibilidade com inimigos (Sono/Resina/Congelamento/Invisibilidade)
    // ------------------------------------------------------------

    private void DrawEnemyCompatibilitySection(ItemData item)
    {
        EditorGUILayout.LabelField("Compatibilidade com Inimigos", EditorStyles.boldLabel);

        var guids = AssetDatabase.FindAssets("t:EnemyData");
        if (guids.Length == 0)
        {
            EditorGUILayout.HelpBox("Nenhum EnemyData encontrado no projecto.", MessageType.Info);
            return;
        }

        GddEnemyItems.TryGetValue(item.itemId, out var gddEntry);
        bool isGddItem = !string.IsNullOrEmpty(item.itemId) && GddEnemyItems.ContainsKey(item.itemId);

        int compatibleCount = 0;
        int incompatibleCount = 0;

        foreach (var guid in guids)
        {
            var path = AssetDatabase.GUIDToAssetPath(guid);
            var enemyData = AssetDatabase.LoadAssetAtPath<EnemyData>(path);
            if (enemyData == null || enemyData.itemInteractions == null) continue;

            var config = enemyData.itemInteractions;
            bool immuneToItem = config.immuneItems != null && config.immuneItems.Contains(item);

            string status = null;
            if (immuneToItem)
            {
                status = "Imune (immuneItems)";
            }
            else if (isGddItem && (bool)GetFlag(config, gddEntry.flagField))
            {
                status = $"Afectado ({gddEntry.effect})";
            }
            else if (config.otherItemEffects != null)
            {
                foreach (var entry in config.otherItemEffects)
                {
                    if (entry != null && entry.item == item)
                    {
                        status = $"Afectado (otherItemEffects → {entry.effect})";
                        break;
                    }
                }
            }

            if (status == null && config.immuneEffects != null && isGddItem && config.immuneEffects.Contains(gddEntry.effect))
                status = $"Imune ao efeito {gddEntry.effect} (immuneEffects)";

            if (status != null)
            {
                compatibleCount++;
                EditorGUILayout.LabelField($"  {enemyData.displayName} ({enemyData.enemyId}): {status}");
            }
            else
            {
                incompatibleCount++;
            }
        }

        if (compatibleCount == 0)
            EditorGUILayout.HelpBox("Nenhum EnemyData está configurado para reagir a este item ainda — verifique \"Interacção com Itens\" no EnemyData de cada inimigo.", MessageType.Info);
        else
            EditorGUILayout.HelpBox($"{incompatibleCount} EnemyData não reagem a este item (sem flag/entrada configurada — não é necessariamente um erro).", MessageType.Info);
    }

    private bool GetFlag(EnemyItemInteractionConfig config, string fieldName)
    {
        switch (fieldName)
        {
            case "canSleepFromSilenceFlower": return config.canSleepFromSilenceFlower;
            case "canBeTrappedByAncientResin": return config.canBeTrappedByAncientResin;
            case "losesTargetFromGoldenDust": return config.losesTargetFromGoldenDust;
            case "canBeFrozenByIceCrystal": return config.canBeFrozenByIceCrystal;
            default: return false;
        }
    }

    // ------------------------------------------------------------
    // Botão de teste (Play Mode)
    // ------------------------------------------------------------

    private void DrawTestButton(ItemData item)
    {
        EditorGUILayout.LabelField("Teste", EditorStyles.boldLabel);

        using (new EditorGUI.DisabledScope(!Application.isPlaying))
        {
            if (GUILayout.Button("Testar Efeito no Player"))
            {
                var user = Object.FindFirstObjectByType<PlayerItemUser>();
                if (user == null)
                {
                    Debug.LogWarning("ItemDataEditor: nenhum PlayerItemUser encontrado na cena.");
                }
                else
                {
                    bool applied = user.ApplyItemEffect(item);
                    Debug.Log(applied
                        ? $"ItemDataEditor: efeito de \"{item.displayName}\" aplicado."
                        : $"ItemDataEditor: \"{item.displayName}\" não teve efeito (sem alvo no raio, ou efeito não aplicável).");
                }
            }
        }

        if (!Application.isPlaying)
            EditorGUILayout.HelpBox("Disponível apenas em Play Mode — aplica o efeito ao PlayerItemUser da cena sem gastar inventário (útil para balancear valores).", MessageType.None);
    }
}
#endif
